diff --git a/programs/escape.c b/programs/escape.c
index 8a90741..2a59d3b 100644
--- a/programs/escape.c
+++ b/programs/escape.c
@@ -26,92 +26,150 @@
 char * ATTRIBUTE_MALLOC
 htmlescape (const char *restrict src, const int cp)
 {
-  int len;
-  char *dest, *d;
-  unsigned char *s;
+  size_t len;
+  char *dest, *d, *tmp;
+  const unsigned char *s;
   if (!src)
     return NULL;
   len = strlen (src) + 10;
-  d = malloc (len);
-  s = (unsigned char *)src;
-  dest = d;
-  while (*s++)
+  dest = malloc (len);
+  if (!dest)
+    return NULL;
+  d = dest;
+  s = (const unsigned char *)src;
+
+  while (*s)
     {
-      const int off = d - dest;
-      if (off >= len - 8)
+      size_t off = d - dest;
+      size_t need = 1;
+      unsigned char ch = *s;
+
+      /* determine how many bytes we will append for this character */
+      switch (ch)
+        {
+        case '"': need = 6; break; /* &quot; */
+        case '\'': need = 5; break; /* &#39; */
+        case '`': need = 5; break; /* &#96; */
+        case '&': need = 5; break; /* &amp; */
+        case '<': need = 4; break; /* &lt; */
+        case '>': need = 4; break; /* &gt; */
+        case '{': need = 6; break; /* &#123; */
+        case '}': need = 6; break; /* &#125; */
+        default:
+          if (ch >= 127)
+            need = 12; /* generous space for &#xHHHH; */
+          else if (ch >= 20)
+            need = 1;
+          else
+            need = 0;
+        }
+
+      if (need > 0 && off + need + 1 >= len)
         {
-          len += 10;
-          dest = realloc (dest, len);
+          size_t newlen = len + need + 16;
+          tmp = realloc (dest, newlen);
+          if (!tmp) { free (dest); return NULL; }
+          dest = tmp;
           d = dest + off;
+          len = newlen;
         }
-      switch (*s)
+
+      switch (ch)
         {
-        case '"': strcat (d, "&quot;"); d += 6; break;
-        case '\'': strcat (d, "&#39;"); d += 5; break;
-        case '`': strcat (d, "&#96;"); d += 5; break;
-        case '&': strcat (d, "&amp;"); d += 5; break;
-        case '<': strcat (d, "&lt;"); d += 4; break;
-        case '>': strcat (d, "&gt;"); d += 4; break;
-        case '{': strcat (d, "&#123;"); d += 6; break;
-        case '}': strcat (d, "&#125;"); d += 6; break;
+        case '"': memcpy (d, "&quot;", 6); d += 6; break;
+        case '\'': memcpy (d, "&#39;", 5); d += 5; break;
+        case '`': memcpy (d, "&#96;", 5); d += 5; break;
+        case '&': memcpy (d, "&amp;", 5); d += 5; break;
+        case '<': memcpy (d, "&lt;", 4); d += 4; break;
+        case '>': memcpy (d, "&gt;", 4); d += 4; break;
+        case '{': memcpy (d, "&#123;", 6); d += 6; break;
+        case '}': memcpy (d, "&#125;", 6); d += 6; break;
         default:
-          if (*s >= 127) // maybe encodings, no utf8 (see htmlwescape)
+          if (ch >= 127)
             {
-              sprintf (d, "&#x%X;", *s); // 4 + 4
-              d += strlen (d);
+              int n = sprintf (d, "&#x%X;", ch);
+              if (n > 0) d += n;
             }
-          else if (*s >= 20)
-            *d++ = *s;
+          else if (ch >= 20)
+            *d++ = ch;
         }
+      s++;
     }
-  *d = 0;
+  *d = '\0';
   return dest;
 }

