     len++;
   len += 16;
-  d = dest = malloc (len);
+  dest = malloc (len);
+  if (!dest)
+    return NULL;
+  d = dest;

-  while (*wstr++)
+  while (*wstr)
     {
-      const int off = d - dest;
-      if (off >= len - 8)
+      size_t off = d - dest;
+      size_t need = 1;
+      BITCODE_RS ch = *wstr;
+
+      switch (ch)
         {
-          len += 16;
-          dest = realloc (dest, len);
+        case 34: need = 6; break; /* &quot; */
+

diff --git a/src/class.c b/src/class.c
