diff --git a/src/njs_string.c b/src/njs_string.c
index d1ae09e..5ca65d0 100644
--- a/src/njs_string.c
+++ b/src/njs_string.c
@@ -2522,21 +2522,20 @@ done:
 const u_char *
 njs_string_offset(const u_char *start, const u_char *end, size_t index)
 {
-    uint32_t    *map;
-    njs_uint_t  skip;
-
-    if (index >= NJS_STRING_MAP_STRIDE) {
-        map = njs_string_map_start(end);
-
-        if (map[0] == 0) {
-            njs_string_offset_map_init(start, end - start);
-        }
-
-        start += map[index / NJS_STRING_MAP_STRIDE - 1];
-    }
+    /*
+     * For safety do not rely on the optional offset map which may not
+     * be allocated for external or ASCII strings.  Fall back to a simple
+     * sequential scan of UTF-8 characters.  This is slower but avoids
+     * dereferencing memory beyond the string end which can lead to
+     * crashes for strings without a following map.
+     */
+    size_t  i;

-    for (skip = index % NJS_STRING_MAP_STRIDE; skip != 0; skip--) {
+    for (i = 0; i < index; i++) {
         start = njs_utf8_next(start, end);
+        if (start >= end) {
+            break;
+        }
     }

     return start;

